SELECT count() AS flights, round(100 * countIf(f.ArrDel15 = 0) / count(), 1) AS on_time_pct, countIf(f.Cancelled = 1) AS cancellations, round(avg(f.DepDelayMinutes), 1) AS avg_departure_delay
FROM ontime.fact_ontime AS f
WHERE f.FlightDate BETWEEN {from:Date} AND {to:Date}
/*[ AND has({carrier:Array(String)}, f.Carrier) ]*/
/*[ AND has({origin:Array(String)}, f.OriginCode) ]*/

SELECT a.DisplayAirportName AS airport, count() AS flights
FROM ontime.fact_ontime AS f
INNER JOIN ontime.dim_airports AS a ON a.AirportCode = f.OriginCode AND a.IsLatest = 1
WHERE f.FlightDate BETWEEN {from:Date} AND {to:Date}
/*[ AND has({carrier:Array(String)}, f.Carrier) ]*/
/*[ AND has({origin:Array(String)}, f.OriginCode) ]*/
GROUP BY airport ORDER BY flights DESC LIMIT 15

SELECT f.FlightDate AS date, count() AS flights
FROM ontime.fact_ontime AS f
WHERE f.FlightDate BETWEEN {from:Date} AND {to:Date}
/*[ AND has({carrier:Array(String)}, f.Carrier) ]*/
/*[ AND has({origin:Array(String)}, f.OriginCode) ]*/
GROUP BY date ORDER BY date

SELECT f.FlightDate AS date, round(100 * countIf(f.ArrDel15 = 0) / count(), 1) AS on_time_pct
FROM ontime.fact_ontime AS f
WHERE f.FlightDate BETWEEN {from:Date} AND {to:Date}
/*[ AND has({carrier:Array(String)}, f.Carrier) ]*/
/*[ AND has({origin:Array(String)}, f.OriginCode) ]*/
GROUP BY date ORDER BY date

SELECT multiIf(f.CancellationCode = 'A', 'Carrier', f.CancellationCode = 'B', 'Weather', f.CancellationCode = 'C', 'National Air System', f.CancellationCode = 'D', 'Security', 'Other') AS reason, count() AS cancellations
FROM ontime.fact_ontime AS f
WHERE f.FlightDate BETWEEN {from:Date} AND {to:Date}
/*[ AND has({carrier:Array(String)}, f.Carrier) ]*/
/*[ AND has({origin:Array(String)}, f.OriginCode) ]*/ AND f.Cancelled = 1
GROUP BY reason ORDER BY cancellations DESC

SELECT toStartOfMonth(f.FlightDate) AS month, f.Carrier AS carrier, count() AS flights
FROM ontime.fact_ontime AS f
WHERE f.FlightDate BETWEEN {from:Date} AND {to:Date}
/*[ AND has({carrier:Array(String)}, f.Carrier) ]*/
/*[ AND has({origin:Array(String)}, f.OriginCode) ]*/
GROUP BY month, carrier ORDER BY month, carrier

SELECT f.Carrier AS carrier, round(avg(f.CarrierDelay), 1) AS carrier_delay, round(avg(f.WeatherDelay), 1) AS weather_delay, round(avg(f.NASDelay), 1) AS nas_delay, round(avg(f.LateAircraftDelay), 1) AS late_aircraft_delay
FROM ontime.fact_ontime AS f
WHERE f.FlightDate BETWEEN {from:Date} AND {to:Date}
/*[ AND has({carrier:Array(String)}, f.Carrier) ]*/
/*[ AND has({origin:Array(String)}, f.OriginCode) ]*/ AND f.ArrDel15 = 1
GROUP BY carrier ORDER BY carrier_delay DESC LIMIT 12
